 // -------------------------------------------------------------------
 // Event handlers
 // -------------------------------------------------------------------
 void MainFrame::onClose(wxCloseEvent& event) {
     // Signal background operations to stop
     controller_->cancelTest();

     // Remove tray icon AND delete the object.
     // wxTaskBarIcon keeps the wxWidgets event loop alive even after
     // all top-level windows are destroyed — without this delete the
     // process never exits and wxEntry in main.cpp never returns.
     if (trayIcon_) {
         trayIcon_->RemoveIcon();
         delete trayIcon_;
         trayIcon_ = nullptr;
     }

     XrayManager::release();  // stop all xray instances immediately
     event.Skip();
 }

 void MainFrame::onIconize(wxIconizeEvent& event) {
     event.Skip();
 }

 void MainFrame::onMenuImportSub(wxCommandEvent&) {
     wxFileDialog dlg(this, "Import Subscription File",
                      wxEmptyString, wxEmptyString,
                      "JSON files (*.json)|*.json|All files (*.*)|*.*",
