 void ProxyDataViewModel::GetValueByRow(wxVariant& variant, unsigned row, unsigned col) const {
     if (row >= proxies_.size()) { variant = wxEmptyString; return; }
     const auto& p = proxies_[row];

     switch (col) {
         case COL_REMARKS:      variant = p.remarks; return;
         case COL_CONFIGTYPE:   variant = p.configtype; return;
         case COL_ADDRESS:      variant = p.address; return;
         case COL_PORT:         variant = p.port; return;
         case COL_NETWORK:      variant = p.network; return;
         case COL_SECURITY:     variant = p.security; return;
         case COL_STREAM_SECURITY: variant = p.streamsecurity; return;
         case COL_SNI:          variant = p.sni; return;
         case COL_ALPN:         variant = p.alpn; return;
         case COL_FINGERPRINT:  variant = p.fingerprint; return;
         case COL_CORETYPE:     variant = p.coretype; return;
         case COL_DELAY:
         case COL_SPEED:
         case COL_MESSAGE: {
             // Look up in exItems
             for (const auto& ex : exItems_) {
                 if (ex.indexid == p.indexid) {
                     switch (col) {
                         case COL_DELAY:   variant = ex.delay; return;
                         case COL_SPEED:   variant = ex.speed; return;
                         case COL_MESSAGE: variant = ex.message; return;
                         default: break;
                     }
                 }
             }
             variant = "-"; return;
         }
         default: variant = wxEmptyString; return;
     }
 }

 bool ProxyDataViewModel::GetAttrByRow(unsigned int row, unsigned int col,
                                        wxDataViewItemAttr& attr) const
 {
     if (row >= proxies_.size()) return false;

     // Color-code config type column
     if (col == COL_CONFIGTYPE) {
         const std::string& ct = proxies_[row].configtype;
         if (ct == "1")       attr.SetColour(wxColor(50, 100, 200));   // VMess - blue
         else if (ct == "3")  attr.SetColour(wxColor(0, 160, 0));      // SS - green
         else if (ct == "4")  attr.SetColour(wxColor(128, 128, 128));  // SOCKS5 - gray
         else if (ct == "5")  attr.SetColour(wxColor(120, 50, 200));   // VLESS - purple
         else if (ct == "6")  attr.SetColour(wxColor(200, 0, 0));      // Trojan - red
         else if (ct == "7")  attr.SetColour(wxColor(220, 120, 0));    // Hysteria2 - orange
         else if (ct == "8")  attr.SetColour(wxColor(0, 180, 180));    // TUIC - cyan
         else if (ct == "9")  attr.SetColour(wxColor(200, 80, 160));   // Juicity - pink
         else if (ct == "10") attr.SetColour(wxColor(180, 160, 0));    // ShadowTLS - yellow
         return true;
     }

     // Color-code delay column
     if (col == COL_DELAY) {
         int delay = getDelay(row);
         if (delay > 0) {
             if (delay < 200)       attr.SetColour(wxColor(0, 160, 0));    // green
             else if (delay < 500)  attr.SetColour(wxColor(200, 160, 0));  // yellow
             else                   attr.SetColour(wxColor(200, 0, 0));    // red
             return true;
         }
     }

     // Check for blacklisted items (high consecutive failures)
     for (const auto& ex : exItems_) {
         if (ex.indexid == proxies_[row].indexid) {
             if (ex.consecutive_failures >= 5) {
                 attr.SetColour(*wxRED);
                 attr.SetBackgroundColour(wxColor(255, 230, 230));
                 return true;
             }
             break;
         }
     }

     return false;
 }

