+// -------------------------------------------------------------------
+// Helpers for Compare
+// -------------------------------------------------------------------
+static int compareStrings(const std::string& a, const std::string& b) {
+    // Case-insensitive comparison
+    std::string al, bl;
+    al.reserve(a.size()); bl.reserve(b.size());
+    for (char c : a) al.push_back(static_cast<char>(std::tolower(static_cast<unsigned char>(c))));
+    for (char c : b) bl.push_back(static_cast<char>(std::tolower(static_cast<unsigned char>(c))));
+    if (al < bl) return -1;
+    if (al > bl) return 1;
+    return 0;
+}
+
+static int compareInts(const std::string& a, const std::string& b) {
+    int ia = 0, ib = 0;
+    try { ia = std::stoi(a); } catch (...) { /* leave as 0 */ }
+    try { ib = std::stoi(b); } catch (...) { /* leave as 0 */ }
+    if (ia < ib) return -1;
+    if (ia > ib) return 1;
+    return 0;
+}
+
+// Compare two ex-item values (delay/speed/message), treating "-" as lowest
+static int compareExValue(const std::string& a, const std::string& b) {
+    bool aValid = (a != "-" && !a.empty());
+    bool bValid = (b != "-" && !b.empty());
+    if (!aValid && !bValid) return 0;
+    if (!aValid) return -1;  // invalid sorts before valid (ascending: invalid last when ascending=false)
+    if (!bValid) return 1;
+    return compareInts(a, b);
+}
+
+// Retrieve the ex-item value for a given row and field name ("delay"/"speed"/"message")
+static std::string getExField(const std::vector<db::models::ProfileExItem>& exItems,
+                               const std::vector<db::models::Profileitem>& proxies,
+                               unsigned int row, const char* field) {
+    if (row >= proxies.size()) return "-";
+    for (const auto& ex : exItems) {
+        if (ex.indexid == proxies[row].indexid) {
+            if (strcmp(field, "delay") == 0) return ex.delay;
+            if (strcmp(field, "speed") == 0) return ex.speed;
+            if (strcmp(field, "message") == 0) return ex.message;
+            break;
+        }
+    }
+    return "-";
+}
+
+// -------------------------------------------------------------------
+// Compare — column header sorting
+// -------------------------------------------------------------------
+int ProxyDataViewModel::Compare(const wxDataViewItem& item1,
+                                 const wxDataViewItem& item2,
+                                 unsigned int column,
+                                 bool ascending) const
+{
+    unsigned int row1 = GetRow(item1);
+    unsigned int row2 = GetRow(item2);
+    if (row1 >= proxies_.size() || row2 >= proxies_.size()) return 0;
+
+    const auto& a = proxies_[row1];
+    const auto& b = proxies_[row2];
+
+    int cmp = 0;
+    switch (column) {
+        case COL_REMARKS:    cmp = compareStrings(a.remarks, b.remarks); break;
+        case COL_CONFIGTYPE: cmp = compareStrings(a.configtype, b.configtype); break;
+        case COL_ADDRESS:    cmp = compareStrings(a.address, b.address); break;
+        case COL_PORT:       cmp = compareInts(a.port, b.port); break;
+        case COL_DELAY: {
+            std::string va = getExField(exItems_, proxies_, row1, "delay");
+            std::string vb = getExField(exItems_, proxies_, row2, "delay");
+            cmp = compareExValue(va, vb);
+            break;
+        }
+        case COL_SPEED: {
+            std::string va = getExField(exItems_, proxies_, row1, "speed");
+            std::string vb = getExField(exItems_, proxies_, row2, "speed");
+            cmp = compareExValue(va, vb);
+            break;
+        }
+        case COL_MESSAGE: {
+            std::string va = getExField(exItems_, proxies_, row1, "message");
+            std::string vb = getExField(exItems_, proxies_, row2, "message");
+            cmp = compareStrings(va, vb);
+            break;
+        }
+        case COL_NETWORK:          cmp = compareStrings(a.network, b.network); break;
+        case COL_SECURITY:         cmp = compareStrings(a.security, b.security); break;
+        case COL_STREAM_SECURITY:  cmp = compareStrings(a.streamsecurity, b.streamsecurity); break;
+        case COL_SNI:              cmp = compareStrings(a.sni, b.sni); break;
+        case COL_ALPN:             cmp = compareStrings(a.alpn, b.alpn); break;
+        case COL_FINGERPRINT:      cmp = compareStrings(a.fingerprint, b.fingerprint); break;
+        case COL_CORETYPE:         cmp = compareStrings(a.coretype, b.coretype); break;
+        default: cmp = 0; break;
+    }
+    return ascending ? cmp : -cmp;
+}
+
