void ProxyListPanel::onTestProxy(wxCommandEvent&) {
    wxDataViewItem item = listCtrl_->GetSelection();
    if (!item.IsOk()) return;
    unsigned int row = model_->GetRow(item);
    auto* proxy = model_->getProxy(row);
    if (!proxy) return;

    // Show start in TestPanel
    if (testPanel_) {
        testPanel_->startTest("Single: " + proxy->remarks);
    }

    auto proxyCopy = *proxy;
    auto cfg = controller_->getConfig();

    // Run test on background thread
    std::thread([this, proxyCopy, cfg]() {
        config::ConfigGenerator gen(db_);
        config::XrayConfig xrayCfg;
        try {
            xrayCfg = gen.generateConfig(proxyCopy);
        } catch (const std::exception& e) {
            wxQueueEvent(testPanel_, new ProxyTestProgressEvent(
                1, 1, proxyCopy.address + ":" + proxyCopy.port,
                proxyCopy.remarks, "-",
                "CONFIG_ERROR: " + std::string(e.what()), true));
            return;
        }

        // Find free ports
        int socksPort = PortManager::findAvailable(cfg.xray_start_port);
        int apiPort = PortManager::findAvailable(cfg.xray_api_port);
        if (socksPort <= 0 || apiPort <= 0) {
            wxQueueEvent(testPanel_, new ProxyTestProgressEvent(
                1, 1, proxyCopy.address + ":" + proxyCopy.port,
                proxyCopy.remarks, "-",
                "No available ports", true));
            return;
        }

        // Build full config: socks inbound + proxy outbound
        std::string configJson =
            "{\"log\":{\"loglevel\":\"warning\"},"
            "\"api\":{\"tag\":\"api\",\"services\":[\"HandlerService\",\"LoggerService\",\"StatsService\"]},"
            "\"stats\":{},"
            "\"policy\":{\"levels\":{\"0\":{\"statsUserUplink\":true,\"statsUserDownlink\":true}},\"system\":{\"statsInboundUplink\":true,\"statsInboundDownlink\":true,\"statsOutboundUplink\":true,\"statsOutboundDownlink\":true}},"
            "\"inbounds\":["
            "{\"tag\":\"api\",\"listen\":\"127.0.0.1\",\"port\":" + std::to_string(apiPort) +
            ",\"protocol\":\"dokodemo-door\",\"settings\":{\"address\":\"127.0.0.1\"}},"
            "{\"tag\":\"socks-in\",\"listen\":\"127.0.0.1\",\"port\":" + std::to_string(socksPort) +
            ",\"protocol\":\"mixed\",\"settings\":{\"auth\":\"noauth\",\"udp\":true}}"
            "],"
            "\"outbounds\":" + xrayCfg.outbound_json + ","
            "\"routing\":{"
            "\"domainStrategy\":\"AsIs\","
            "\"rules\":["
            "{\"type\":\"field\",\"inboundTag\":[\"api\"],\"outboundTag\":\"api\"},"
            "{\"type\":\"field\",\"outboundTag\":\"proxy\",\"network\":\"tcp\"}"
            "]}}";

        // Write config to temp file
        std::string configDir = std::filesystem::temp_directory_path().string();
        std::string configPath = configDir + "/xray_single_" + std::to_string(socksPort) + ".json";
        {
            std::ofstream out(configPath);
            if (!out.is_open()) {
                wxQueueEvent(testPanel_, new ProxyTestProgressEvent(
                    1, 1, proxyCopy.address + ":" + proxyCopy.port,
                    proxyCopy.remarks, "-",
                    "Failed to create config file", true));
                return;
            }
            out << configJson;
            out.close();
        }

        // Start xray process
        std::string cmd = "\"" + cfg.xray_executable + "\" run -c \"" + configPath + "\"";

        STARTUPINFOA si = {};
        si.cb = sizeof(si);
        PROCESS_INFORMATION pi = {};
        BOOL created = CreateProcessA(NULL, (LPSTR)cmd.c_str(), NULL, NULL,
                                       FALSE, CREATE_NO_WINDOW, NULL, NULL, &si, &pi);
        if (!created) {
            std::error_code ec;
            std::filesystem::remove(configPath, ec);
            wxQueueEvent(testPanel_, new ProxyTestProgressEvent(
                1, 1, proxyCopy.address + ":" + proxyCopy.port,
                proxyCopy.remarks, "-",
                "Failed to start xray: " + std::to_string(GetLastError()), true));
            return;
        }

        CloseHandle(pi.hThread);

        // Wait for xray to start
        std::this_thread::sleep_for(std::chrono::milliseconds(2000));

        // Test the proxy
        ProxyTester tester(nullptr, cfg.test_url, cfg.test_timeout_ms);
        TestResult result = tester.test(socksPort);

        // Stop xray
        TerminateProcess(pi.hProcess, 0);
        CloseHandle(pi.hProcess);

        // Clean up config file
        std::error_code ec;
        std::filesystem::remove(configPath, ec);

        // Post result to TestPanel
        std::string delayStr = result.success ? std::to_string(result.latencyMs) + "ms" : "-";
        std::string msgStr = result.success ? "OK" : (result.errorMsg.empty() ? "TIMEOUT/FAILED" : result.errorMsg);

        wxQueueEvent(testPanel_, new ProxyTestProgressEvent(
            1, 1, proxyCopy.address + ":" + proxyCopy.port,
            proxyCopy.remarks, delayStr, msgStr, true));
    }).detach();
}

