// -------------------------------------------------------------------
// sortByColumn — reorder proxies_ vector by the given column
// Called from onColumnHeaderClick to actually sort displayed data
// -------------------------------------------------------------------
void ProxyDataViewModel::sortByColumn(unsigned int column, bool ascending) {
    std::sort(proxies_.begin(), proxies_.end(),
        [this, column, ascending](const db::models::Profileitem& a,
                                   const db::models::Profileitem& b) {
        int cmp = 0;
        switch (column) {
            case COL_REMARKS:    cmp = compareStrings(a.remarks, b.remarks); break;
            case COL_CONFIGTYPE: cmp = compareStrings(a.configtype, b.configtype); break;
            case COL_ADDRESS:    cmp = compareStrings(a.address, b.address); break;
            case COL_PORT:       cmp = compareInts(a.port, b.port); break;
            case COL_DELAY: {
                // Need row index — search by indexid
                auto row1 = std::distance(proxies_.data(), &a);
                auto row2 = std::distance(proxies_.data(), &b);
                std::string va = getExField(exItems_, proxies_,
                    static_cast<unsigned int>(row1), "delay");
                std::string vb = getExField(exItems_, proxies_,
                    static_cast<unsigned int>(row2), "delay");
                cmp = compareExValue(va, vb);
                break;
            }
            case COL_SPEED: {
                auto row1 = std::distance(proxies_.data(), &a);
                auto row2 = std::distance(proxies_.data(), &b);
                std::string va = getExField(exItems_, proxies_,
                    static_cast<unsigned int>(row1), "speed");
                std::string vb = getExField(exItems_, proxies_,
                    static_cast<unsigned int>(row2), "speed");
                cmp = compareExValue(va, vb);
                break;
            }
            case COL_MESSAGE: {
                auto row1 = std::distance(proxies_.data(), &a);
                auto row2 = std::distance(proxies_.data(), &b);
                std::string va = getExField(exItems_, proxies_,
                    static_cast<unsigned int>(row1), "message");
                std::string vb = getExField(exItems_, proxies_,
                    static_cast<unsigned int>(row2), "message");
                cmp = compareStrings(va, vb);
                break;
            }
            case COL_NETWORK:          cmp = compareStrings(a.network, b.network); break;
            case COL_SECURITY:         cmp = compareStrings(a.security, b.security); break;
            case COL_STREAM_SECURITY:  cmp = compareStrings(a.streamsecurity, b.streamsecurity); break;
            case COL_SNI:              cmp = compareStrings(a.sni, b.sni); break;
            case COL_ALPN:             cmp = compareStrings(a.alpn, b.alpn); break;
            case COL_FINGERPRINT:      cmp = compareStrings(a.fingerprint, b.fingerprint); break;
            case COL_CORETYPE:         cmp = compareStrings(a.coretype, b.coretype); break;
