void ProxyListPanel::onColumnHeaderClick(wxDataViewEvent& event) {
    // Get the sorting column and direction from the control
    wxDataViewColumn* col = listCtrl_->GetSortingColumn();
    if (!col) { event.Skip(); return; }

    unsigned int colIdx = col->GetModelColumn();
    bool ascending = (col->GetSortOrder() == wxDATAVIEW_SORT_ASCENDING);

    // Actually sort the model's data vector
    model_->sortByColumn(colIdx, ascending);
}

