+}
+
+void SubscriptionPanel::showEditDialog(const db::models::Subitem& sub) {
+    wxDialog dlg(this, wxID_ANY, "Edit Subscription", wxDefaultPosition, wxSize(500, 400));
+    wxBoxSizer* topSizer = new wxBoxSizer(wxVERTICAL);
