 ProxyDataViewModel::ProxyDataViewModel() {
     // Reserve space
     proxies_.reserve(50000);
     exItems_.reserve(50000);
 }

 void ProxyDataViewModel::setData(
     const std::vector<db::models::Profileitem>& proxies,
     const std::vector<db::models::ProfileExItem>& exItems)
 {
     proxies_ = proxies;
     exItems_ = exItems;
     Reset(static_cast<unsigned int>(proxies_.size()));
 }

 void ProxyDataViewModel::clear() {
     proxies_.clear();
     exItems_.clear();
     Reset(0);
 }

 void ProxyDataViewModel::GetValueByRow(wxVariant& variant, unsigned row, unsigned col) const {
     if (row >= proxies_.size()) { variant = wxEmptyString; return; }
     const auto& p = proxies_[row];

     switch (col) {
         case COL_REMARKS:      variant = p.remarks; return;
         case COL_CONFIGTYPE:   variant = p.configtype; return;
         case COL_ADDRESS:      variant = p.address; return;
         case COL_PORT:         variant = p.port; return;
         case COL_NETWORK:      variant = p.network; return;
         case COL_SECURITY:     variant = p.security; return;
         case COL_STREAM_SECURITY: variant = p.streamsecurity; return;
         case COL_SNI:          variant = p.sni; return;
         case COL_ALPN:         variant = p.alpn; return;
         case COL_FINGERPRINT:  variant = p.fingerprint; return;
         case COL_CORETYPE:     variant = p.coretype; return;
         case COL_DELAY:
         case COL_SPEED:
         case COL_MESSAGE: {
             // Look up in exItems
             for (const auto& ex : exItems_) {
                 if (ex.indexid == p.indexid) {
                     switch (col) {
                         case COL_DELAY:   variant = ex.delay; return;
                         case COL_SPEED:   variant = ex.speed; return;
                         case COL_MESSAGE: variant = ex.message; return;
                         default: break;
                     }
                 }
             }
             variant = "-"; return;
         }
         default: variant = wxEmptyString; return;
     }
 }

 bool ProxyDataViewModel::GetAttrByRow(unsigned int row, unsigned int col,
                                        wxDataViewItemAttr& attr) const
 {
     if (row >= proxies_.size()) return false;

     // Color-code config type column
     if (col == COL_CONFIGTYPE) {
         const std::string& ct = proxies_[row].configtype;
         if (ct == "1")       attr.SetColour(wxColor(50, 100, 200));   // VMess - blue
         else if (ct == "3")  attr.SetColour(wxColor(0, 160, 0));      // SS - green
         else if (ct == "4")  attr.SetColour(wxColor(128, 128, 128));  // SOCKS5 - gray
         else if (ct == "5")  attr.SetColour(wxColor(120, 50, 200));   // VLESS - purple
         else if (ct == "6")  attr.SetColour(wxColor(200, 0, 0));      // Trojan - red
         else if (ct == "7")  attr.SetColour(wxColor(220, 120, 0));    // Hysteria2 - orange
         else if (ct == "8")  attr.SetColour(wxColor(0, 180, 180));    // TUIC - cyan
         else if (ct == "9")  attr.SetColour(wxColor(200, 80, 160));   // Juicity - pink
         else if (ct == "10") attr.SetColour(wxColor(180, 160, 0));    // ShadowTLS - yellow
         return true;
     }

     // Color-code delay column
     if (col == COL_DELAY) {
         int delay = getDelay(row);
         if (delay > 0) {
             if (delay < 200)       attr.SetColour(wxColor(0, 160, 0));    // green
             else if (delay < 500)  attr.SetColour(wxColor(200, 160, 0));  // yellow
             else                   attr.SetColour(wxColor(200, 0, 0));    // red
             return true;
         }
     }

     // Check for blacklisted items (high consecutive failures)
     for (const auto& ex : exItems_) {
         if (ex.indexid == proxies_[row].indexid) {
             if (ex.consecutive_failures >= 5) {
                 attr.SetColour(*wxRED);
                 attr.SetBackgroundColour(wxColor(255, 230, 230));
                 return true;
             }
             break;
         }
     }

     return false;
 }

 bool ProxyDataViewModel::SetValueByRow(const wxVariant&, unsigned int, unsigned int) {
     return false; // read-only
 }

 wxDataViewItem ProxyDataViewModel::GetItemByRow(unsigned int row) const {
     return wxDataViewItem((void*)(size_t)(row + 1));
 }

 const db::models::Profileitem* ProxyDataViewModel::getProxy(unsigned int row) const {
     if (row < proxies_.size()) return &proxies_[row];
     return nullptr;
 }

 int ProxyDataViewModel::getDelay(unsigned int row) const {
     if (row >= proxies_.size()) return -1;
     for (const auto& ex : exItems_) {
         if (ex.indexid == proxies_[row].indexid) {
             try { return std::stoi(ex.delay); }
             catch (...) { return -1; }
         }
     }
     return -1;
 }

 // -------------------------------------------------------------------
 // Helpers for Compare
 // -------------------------------------------------------------------
 static int compareStrings(const std::string& a, const std::string& b) {
     // Case-insensitive comparison
     std::string al, bl;
     al.reserve(a.size()); bl.reserve(b.size());
     for (char c : a) al.push_back(static_cast<char>(std::tolower(static_cast<unsigned char>(c))));
     for (char c : b) bl.push_back(static_cast<char>(std::tolower(static_cast<unsigned char>(c))));
     if (al < bl) return -1;
     if (al > bl) return 1;
     return 0;
 }

 static int compareInts(const std::string& a, const std::string& b) {
     int ia = 0, ib = 0;
     try { ia = std::stoi(a); } catch (...) { /* leave as 0 */ }
     try { ib = std::stoi(b); } catch (...) { /* leave as 0 */ }
     if (ia < ib) return -1;
     if (ia > ib) return 1;
     return 0;
 }

 // Compare two ex-item values (delay/speed/message), treating "-" as lowest
 static int compareExValue(const std::string& a, const std::string& b) {
     bool aValid = (a != "-" && !a.empty());
     bool bValid = (b != "-" && !b.empty());
     if (!aValid && !bValid) return 0;
     if (!aValid) return -1;  // invalid sorts before valid (ascending: invalid last when ascending=false)
     if (!bValid) return 1;
     return compareInts(a, b);
 }

 // Retrieve the ex-item value for a given row and field name ("delay"/"speed"/"message")
 static std::string getExField(const std::vector<db::models::ProfileExItem>& exItems,
                                const std::vector<db::models::Profileitem>& proxies,
                                unsigned int row, const char* field) {
     if (row >= proxies.size()) return "-";
     for (const auto& ex : exItems) {
         if (ex.indexid == proxies[row].indexid) {
             if (strcmp(field, "delay") == 0) return ex.delay;
             if (strcmp(field, "speed") == 0) return ex.speed;
             if (strcmp(field, "message") == 0) return ex.message;
             break;
         }
     }
     return "-";
 }

 // Look up ex field value by indexid directly (for use in sort comparator)
 static std::string getExFieldByIndexId(const std::vector<db::models::ProfileExItem>& exItems,
                                         const std::string& indexid, const char* field) {
     for (const auto& ex : exItems) {
         if (ex.indexid == indexid) {
             if (strcmp(field, "delay") == 0) return ex.delay;
             if (strcmp(field, "speed") == 0) return ex.speed;
             if (strcmp(field, "message") == 0) return ex.message;
             break;
         }
     }
     return "-";
 }

 // -------------------------------------------------------------------
 // Compare — column header sorting
 // -------------------------------------------------------------------
 int ProxyDataViewModel::Compare(const wxDataViewItem& item1,
                                  const wxDataViewItem& item2,
                                  unsigned int column,
                                  bool ascending) const
 {
     unsigned int row1 = GetRow(item1);
     unsigned int row2 = GetRow(item2);
     if (row1 >= proxies_.size() || row2 >= proxies_.size()) return 0;

     const auto& a = proxies_[row1];
     const auto& b = proxies_[row2];

     int cmp = 0;
     switch (column) {
         case COL_REMARKS:    cmp = compareStrings(a.remarks, b.remarks); break;
         case COL_CONFIGTYPE: cmp = compareStrings(a.configtype, b.configtype); break;
         case COL_ADDRESS:    cmp = compareStrings(a.address, b.address); break;
         case COL_PORT:       cmp = compareInts(a.port, b.port); break;
         case COL_DELAY: {
             std::string va = getExField(exItems_, proxies_, row1, "delay");
             std::string vb = getExField(exItems_, proxies_, row2, "delay");
             cmp = compareExValue(va, vb);
             break;
         }
         case COL_SPEED: {
             std::string va = getExField(exItems_, proxies_, row1, "speed");
             std::string vb = getExField(exItems_, proxies_, row2, "speed");
             cmp = compareExValue(va, vb);
             break;
         }
         case COL_MESSAGE: {
             std::string va = getExField(exItems_, proxies_, row1, "message");
             std::string vb = getExField(exItems_, proxies_, row2, "message");
             cmp = compareStrings(va, vb);
             break;
         }
         case COL_NETWORK:          cmp = compareStrings(a.network, b.network); break;
         case COL_SECURITY:         cmp = compareStrings(a.security, b.security); break;
         case COL_STREAM_SECURITY:  cmp = compareStrings(a.streamsecurity, b.streamsecurity); break;
         case COL_SNI:              cmp = compareStrings(a.sni, b.sni); break;
         case COL_ALPN:             cmp = compareStrings(a.alpn, b.alpn); break;
         case COL_FINGERPRINT:      cmp = compareStrings(a.fingerprint, b.fingerprint); break;
         case COL_CORETYPE:         cmp = compareStrings(a.coretype, b.coretype); break;
         default: cmp = 0; break;
     }
     return ascending ? cmp : -cmp;
 }

 // -------------------------------------------------------------------
 // sortByColumn — reorder proxies_ vector by the given column
 // Called from onColumnHeaderClick to actually sort displayed data
 // -------------------------------------------------------------------
 void ProxyDataViewModel::sortByColumn(unsigned int column, bool ascending) {
     std::sort(proxies_.begin(), proxies_.end(),
         [this, column, ascending](const db::models::Profileitem& a,
                                    const db::models::Profileitem& b) {
         int cmp = 0;
         switch (column) {
             case COL_REMARKS:    cmp = compareStrings(a.remarks, b.remarks); break;
             case COL_CONFIGTYPE: cmp = compareStrings(a.configtype, b.configtype); break;
             case COL_ADDRESS:    cmp = compareStrings(a.address, b.address); break;
             case COL_PORT:       cmp = compareInts(a.port, b.port); break;
             case COL_DELAY: {
                 std::string va = getExFieldByIndexId(exItems_, a.indexid, "delay");
                 std::string vb = getExFieldByIndexId(exItems_, b.indexid, "delay");
                 cmp = compareExValue(va, vb);
                 break;
             }
             case COL_SPEED: {
                 std::string va = getExFieldByIndexId(exItems_, a.indexid, "speed");
                 std::string vb = getExFieldByIndexId(exItems_, b.indexid, "speed");
                 cmp = compareExValue(va, vb);
                 break;
             }
             case COL_MESSAGE: {
                 std::string va = getExFieldByIndexId(exItems_, a.indexid, "message");
                 std::string vb = getExFieldByIndexId(exItems_, b.indexid, "message");
                 cmp = compareStrings(va, vb);
                 break;
             }
             case COL_NETWORK:          cmp = compareStrings(a.network, b.network); break;
             case COL_SECURITY:         cmp = compareStrings(a.security, b.security); break;
             case COL_STREAM_SECURITY:  cmp = compareStrings(a.streamsecurity, b.streamsecurity); break;
             case COL_SNI:              cmp = compareStrings(a.sni, b.sni); break;
             case COL_ALPN:             cmp = compareStrings(a.alpn, b.alpn); break;
             case COL_FINGERPRINT:      cmp = compareStrings(a.fingerprint, b.fingerprint); break;
             case COL_CORETYPE:         cmp = compareStrings(a.coretype, b.coretype); break;
             default: cmp = 0; break;
         }
         return ascending ? (cmp < 0) : (cmp > 0);
     });

     // Notify the control that data has changed
     Reset(static_cast<unsigned int>(proxies_.size()));
 }

