 // Column labels
 static const char* COLUMN_LABELS[] = {
     "Remarks", "Type", "Address", "Port",
     "Delay", "Speed", "Message",
     "Network", "Security", "Stream Security",
     "SNI", "ALPN", "Fingerprint", "Core Type"
 };
 static const int COL_COUNT = sizeof(COLUMN_LABELS) / sizeof(COLUMN_LABELS[0]);

