 ProxyListPanel::ProxyListPanel(wxWindow* parent, AppController* controller,
                                sqlite3* db, TestPanel* testPanel)
     : wxPanel(parent, wxID_ANY),
       controller_(controller), db_(db), testPanel_(testPanel)
 {
     wxBoxSizer* topSizer = new wxBoxSizer(wxVERTICAL);

     // Filter toolbar
     wxBoxSizer* filterSizer = new wxBoxSizer(wxHORIZONTAL);

     filterSizer->Add(new wxStaticText(this, wxID_ANY, "Type:"), 0,
                       wxALIGN_CENTER_VERTICAL | wxRIGHT, 4);
     wxArrayString types;
     types.Add("All"); types.Add("VMess"); types.Add("SS"); types.Add("SOCKS5");
     types.Add("VLESS"); types.Add("Trojan"); types.Add("Hysteria2");
     types.Add("TUIC"); types.Add("ShadowTLS");
     typeFilter_ = new wxChoice(this, ID_PROXY_FILTER_TYPE, wxDefaultPosition,
                                 wxSize(100, -1), types);
     typeFilter_->SetSelection(0);
     filterSizer->Add(typeFilter_, 0, wxRIGHT, 8);

     filterSizer->Add(new wxStaticText(this, wxID_ANY, "Status:"), 0,
                       wxALIGN_CENTER_VERTICAL | wxRIGHT, 4);
     wxArrayString statuses;
     statuses.Add("All"); statuses.Add("Valid"); statuses.Add("Invalid"); statuses.Add("Untested");
     statusFilter_ = new wxChoice(this, ID_PROXY_FILTER_STATUS, wxDefaultPosition,
                                   wxSize(100, -1), statuses);
     statusFilter_->SetSelection(0);
     filterSizer->Add(statusFilter_, 0, wxRIGHT, 8);

     searchCtrl_ = new wxSearchCtrl(this, ID_PROXY_SEARCH);
     searchCtrl_->SetDescriptiveText("Search...");
     searchCtrl_->SetMinSize(wxSize(200, -1));
     filterSizer->Add(searchCtrl_, 1, wxEXPAND);

     topSizer->Add(filterSizer, 0, wxEXPAND | wxALL, 4);

     // Data view control
     model_ = new ProxyDataViewModel();
     listCtrl_ = new wxDataViewCtrl(this, wxID_ANY,
                                     wxDefaultPosition, wxDefaultSize,
                                     wxDV_ROW_LINES | wxDV_SINGLE | wxDV_VARIABLE_LINE_HEIGHT);
     listCtrl_->AssociateModel(model_);
     model_->DecRef(); // AssociateModel took ownership

     // Append columns from labels
     int widths[] = { 150, 60, 130, 60, 60, 60, 200, 60, 60, 80, 100, 80, 80, 60 };
     static_assert(sizeof(widths)/sizeof(widths[0]) == COL_COUNT, "widths/columns mismatch");

     for (int i = 0; i < COL_COUNT; ++i) {
         listCtrl_->AppendTextColumn(COLUMN_LABELS[i], i,
                                      wxDATAVIEW_CELL_INERT, widths[i],
                                      wxALIGN_LEFT,
                                      wxDATAVIEW_COL_RESIZABLE | wxDATAVIEW_COL_SORTABLE);
     }

     topSizer->Add(listCtrl_, 1, wxEXPAND | wxALL, 2);

     // Status bar
     wxBoxSizer* statusSizer = new wxBoxSizer(wxHORIZONTAL);
     wxStaticText* countLabel = new wxStaticText(this, wxID_ANY, "Proxies:");
     statusSizer->Add(countLabel, 0, wxRIGHT, 4);
     wxStaticText* countValue = new wxStaticText(this, wxID_ANY, "0");
     countValue->SetName("proxyCount");
     statusSizer->Add(countValue, 0);
     statusSizer->AddStretchSpacer();
     topSizer->Add(statusSizer, 0, wxEXPAND | wxALL, 2);

     SetSizer(topSizer);

     // Bind custom events
     Bind(wxEVT_SUBSCRIPTION_SELECTED, [this](SubscriptionSelectedEvent& event) {
         loadProxies(event.getSubId());
     });
 }

 void ProxyListPanel::loadProxies(const std::string& subId) {
     currentSubId_ = subId;
     allProxies_ = controller_->loadProxies(subId);
     exItems_ = controller_->loadProxyResults();
     model_->setData(allProxies_, exItems_);

     // Update count
     wxStaticText* countLabel = dynamic_cast<wxStaticText*>(FindWindowByName("proxyCount"));
     if (countLabel) {
         countLabel->SetLabel(wxString::Format("%zu", allProxies_.size()));
     }

     Logger::write("Loaded " + std::to_string(allProxies_.size()) + " proxies", LogLevel::DEBUG);
 }

